import{_ as r,a,b as o,m as t}from"./chunks/framework.DhA78p7M.js";const w=JSON.parse('{"title":"KERNN v1 - Building A General Feed Forward Neural Network Accelerator","description":"How I built a general purpose feed forward neural network accelerator","frontmatter":{"title":"KERNN v1 - Building A General Feed Forward Neural Network Accelerator","description":"How I built a general purpose feed forward neural network accelerator","longDescription":"","date":"2026-4-10"},"headers":[],"relativePath":"blogs/kernn/index.md","filePath":"blogs/kernn/index.md"}'),n={name:"blogs/kernn/index.md"};function i(l,e,d,s,c,h){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="kernn-v1-building-a-general-deep-neural-network-accelerator" tabindex="-1">KERNN v1 - Building A General Deep Neural Network Accelerator <a class="header-anchor" href="#kernn-v1-building-a-general-deep-neural-network-accelerator" aria-label="Permalink to “KERNN v1 - Building A General Deep Neural Network Accelerator”">​</a></h1><p>AI, something we can&#39;t seem to escape from. It feels like wherever I go, I can&#39;t escape from yet another company touting their new AI application. Admittedly, some of these are pretty cool though. As a hardware person, I&#39;ve honestly ignored AI for the most part, instead building hearing aids and signal processing accelerators.</p><p>However, over winter break, I had the opportunity to explore GPU architecture and write CUDA/ROC-M kernals, and I gained an appreciatation for the low level hardware behind AI, so I figured I&#39;d build a neural network accelerator myself.</p><h2 id="what-does-it-do" tabindex="-1">What does it do? <a class="header-anchor" href="#what-does-it-do" aria-label="Permalink to “What does it do?”">​</a></h2><p>What does it mean to accelerate a Feed Forward Neural Network? It means doing matrix multiplication, really really fast. Now, there are some other operations but those are far less computationally complex. Beyond that, there isn&#39;t really much more computational work.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to “How does it work?”">​</a></h2><p>The core of the design is a systolic array, which performs the matrix multiplication. All of the other hardware is either for control flow, or helps feed a systolic array.</p><h1 id="work-in-progess-mb" tabindex="-1">WORK IN PROGESS, mb. <a class="header-anchor" href="#work-in-progess-mb" aria-label="Permalink to “WORK IN PROGESS, mb.”">​</a></h1>',8)])])}const m=r(n,[["render",i]]);export{w as __pageData,m as default};
